{
 "level": "A2‚ÄìB1",
 "intro": "In this topic you will learn the <strong>differences between each, every and all</strong> - three ways to say \"each\" or \"everyone\".",
 "rules": [
 {
 "label": "EACH",
 "color": "emerald",
 "text": "<strong>Each</strong> - each one separately (individually):",
 "example": "Each student has a book. (each his own)"
 },
 {
 "label": "EVERY",
 "color": "blue",
 "text": "<strong>Every</strong> - everyone without exception (group):",
 "example": "Every student passed. (all as a group)"
 },
 {
 "label": "ALL",
 "color": "amber",
 "text": "<strong>All</strong> - all together (generality):",
 "example": "All students are here. (all together)"
 }
 ]
}

{
 "title": "1. Main differences",
 "intro": "Main characteristics of each, every and all:",
 "rows": [
 {
 "en": "each",
 "ua": "each",
 "note": "+ singular noun/verb. Individually."
 },
 {
 "en": "every",
 "ua": "every",
 "note": "+ singular noun/verb. As a group."
 },
 {
 "en": "all",
 "ua": "all",
 "note": "+ plural noun/verb. Generality."
 }
 ],
 "warning": "üìå Each/every + singular. All + plural."
}

{
 "title": "2. EACH - each separately",
 "sections": [
 {
 "label": "Each = individually",
 "color": "emerald",
 "description": "<strong>Each</strong> means \"each separately\" - focus on individuality, on each element separately.",
 "examples": [
 {
 "en": "Each student has a book.",
 "ua": "Each student has a book."
 },
 {
 "en": "Each person is different.",
 "ua": "Each person is different."
 },
 {
 "en": "I gave each child a toy.",
 "ua": "I gave each child a toy."
 }
 ]
 },
 {
 "label": "Each + singular",
 "color": "sky",
 "description": "<strong>Each</strong> always with a <strong>noun and a singular verb</strong>.",
 "examples": [
 {
 "en": "Each student has... (‚úì)",
 "ua": "Each student has... (‚úì)"
 },
 {
 "en": "Each student have... (‚úó)",
 "ua": "Each student have... (‚úó)"
 },
 {
 "en": "Each book is interesting.",
 "ua": "Each book is interesting."
 }
 ],
 "note": "üìå Each always + singular (is, has, does)."
 },
 {
 "label": "Each of + plural noun",
 "color": "purple",
 "description": "You can use <strong>each of + the/these/those + plural noun</strong>. The verb is singular!",
 "examples": [
 {
 "en": "Each of the students has a book.",
 "ua": "Each of the students has a book."
 },
 {
 "en": "Each of these books is good.",
 "ua": "Each of these books is good."
 }
 ],
 "note": "Each of + plural, but verb singular!"
 }
 ]
}

{
 "title": "3. EVERY - everyone without exception",
 "sections": [
 {
 "label": "Every = as a group",
 "color": "blue",
 "description": "<strong>Every</strong> means \"everyone without exception\" ‚Äî focus on the group as a whole, everyone without exception.",
 "examples": [
 {
 "en": "Every student passed the exam.",
 "ua": "Every student passed the exam."
 },
 {
 "en": "Every day I go to work.",
 "ua": "Every day I go to work."
 },
 {
 "en": "Every person needs food.",
 "ua": "Every person needs food."
 }
 ]
 },
 {
 "label": "Every + singular",
 "color": "sky",
 "description": "<strong>Every</strong> is always with a <strong>noun and a singular verb</strong>.",
 "examples": [
 {
 "en": "Every student is... (‚úì)",
 "ua": "Every student is... (‚úì)"
 },
 {
 "en": "Every student are... (‚úó)",
 "ua": "Every student are... (‚úó)"
 },
 {
 "en": "Every child needs love.",
 "ua": "Every child needs love."
 }
 ],
 "note": "üìå Every always + singular (is, has, does)."
 },
 {
 "label": "Every + time expressions",
 "color": "purple",
 "description": "<strong>Every</strong> is often used with time expressions.",
 "examples": [
 {
 "en": "every day, every week, every month, every year",
 "ua": "every day, every week, every month, every year"
 },
 {
 "en": "I exercise every day.",
 "ua": "I exercise every day."
 },
 {
 "en": "We meet every Friday.",
 "ua": "We meet every Friday."
 }
 ],
 "note": "Every = every day, every week (regularity)."
 },
 {
 "label": "NOT possible: Every of",
 "color": "rose",
 "description": "There is NO construction <strong>every of</strong>! Use each of or all of.",
 "examples": [
 {
 "en": "Every of the students... (‚úó)",
 "ua": "Every of the students... (‚úó)"
 },
 {
 "en": "Each of the students... (‚úì)",
 "ua": "Each of the students... (‚úì)"
 },
 {
 "en": "All of the students... (‚úì)",
 "ua": "All of the students... (‚úì)"
 }
 ],
 "note": "üìå There is no \"every of\"! Only each of or all of."
 }
 ]
}

{
 "title": "4. ALL - all together",
 "sections": [
 {
 "label": "All = generality",
 "color": "amber",
 "description": "<strong>All</strong> means \"all\" or \"everything\" ‚Äî focus on generality, on everyone together.",
 "examples": [
 {
 "en": "All students are here.",
 "ua": "All students are here."
 },
 {
 "en": "All people need love.",
 "ua": "All people need love."
 },
 {
 "en": "I ate all the cookies.",
 "ua": "I ate all the cookies."
 }
 ]
 },
 {
 "label": "All + plural",
 "color": "sky",
 "description": "Use the pattern in the examples and focus on the highlighted words.",
 "examples": [
 {
 "en": "All students are... (‚úì)",
 "ua": "All students are... (‚úì)"
 },
 {
 "en": "All students is... (‚úó)",
 "ua": "All students is... (‚úó)"
 },
 {
 "en": "All the books are interesting.",
 "ua": "All the books are interesting."
 }
 ],
 "note": "üìå All (plural) + plural verb (are, have, do)."
 },
 {
 "label": "All + uncountable",
 "color": "purple",
 "description": "<strong>All</strong> is also used with uncountable nouns (singular verb).",
 "examples": [
 {
 "en": "All water is important.",
 "ua": "All water is important."
 },
 {
 "en": "All information is correct.",
 "ua": "All information is correct."
 }
 ],
 "note": "All + uncountable ‚Üí singular verb."
 },
 {
 "label": "All of + the/these/my",
 "color": "emerald",
 "description": "With the article, demonstrative or possessive words, we use <strong>all of</strong>.",
 "examples": [
 {
 "en": "All of the students are all of these books are mine. the/these/those/my/your.",
 "ua": "All of the students are all of these books are mine. the/these/those/my/your."
 },
 {
 "en": "All of these books are mine.",
 "ua": "All of these books are mine."
 },
 {
 "en": "All of my friends came.",
 "ua": "All of my friends came."
 }
 ],
 "note": "üìå All of + the/these/those/my/your."
 }
 ]
}

{
 "title": "5. Each vs Each - when to use what <strong>Every</strong> - when considered as a group.",
 "sections": [
 {
 "label": "Individual focus vs group focus",
 "color": "emerald",
 "description": "Use the pattern in the examples and focus on the highlighted words.",
 "examples": [
 {
 "en": "Each student has different needs. (individual)",
 "ua": "Each student has different needs. (individual)"
 },
 {
 "en": "Every student must pass the exam. (all as a group)",
 "ua": "Every student must pass the exam. (all as a group)"
 }
 ]
 },
 {
 "label": "Each - for small groups",
 "color": "blue",
 "description": "<strong>Each</strong> more often for small groups (2-10). Every is for any size. (large group)",
 "examples": [
 {
 "en": "Each of my three cats...",
 "ua": "Each of my three cats..."
 },
 {
 "en": "Every citizen has rights.",
 "ua": "Every citizen has rights."
 }
 ],
 "note": "Each = small groups. Every = any size."
 },
 {
 "label": "Each can be after a noun",
 "color": "sky",
 "description": "<strong>Each</strong> can be after a noun. <strong>Every</strong> - only before.",
 "examples": [
 {
 "en": "The students each have a book. (‚úì)",
 "ua": "The students each have a book. (‚úì)"
 },
 {
 "en": "The students each have a book. (‚úó)",
 "ua": "The students each have a book. (‚úó)"
 }
 ],
 "note": "üìå Each can after noun. Every - only before."
 }
 ]
}

{
 "title": "6. Every vs All - when to use",
 "sections": [
 {
 "label": "Every + singular, All + plural",
 "color": "amber",
 "description": "The main difference: <strong>every + singular</strong>, <strong>all + plural</strong>.",
 "examples": [
 {
 "en": "Every student is... (singular)",
 "ua": "Every student is... (singular)"
 },
 {
 "en": "All students are... (plural)",
 "ua": "All students are... (plural)"
 }
 ]
 },
 {
 "label": "All - when there is a specific group",
 "color": "blue",
 "description": "<strong>All</strong> - when we are talking about a specific, defined group.",
 "examples": [
 {
 "en": "All the students in my class passed.",
 "ua": "All the students in my class passed."
 },
 {
 "en": "Every student must study. (in general)",
 "ua": "Every student must study. (in general)"
 }
 ],
 "note": "All = specific group. Every = general rule."
 },
 {
 "label": "All can be independent",
 "color": "sky",
 "description": "<strong>All</strong> can stand alone without a noun. <strong>Every</strong> - no.",
 "examples": [
 {
 "en": "All are welcome. (‚úì)",
 "ua": "All are welcome. (‚úì)"
 },
 {
 "en": "Every are welcome. (‚úó)",
 "ua": "Every are welcome. (‚úó)"
 }
 ],
 "note": "üìå All can do it independently. Every - only + noun."
 }
 ]
}

{
 "title": "7. Position in a sentence",
 "sections": [
 {
 "label": "Each is a flexible position",
 "color": "emerald",
 "description": "<strong>Each</strong> can be: before a noun, after a noun, or at the end.",
 "examples": [
 {
 "en": "Each student has a book.",
 "ua": "Each student has a book."
 },
 {
 "en": "The students each have a book.",
 "ua": "The students each have a book."
 },
 {
 "en": "They cost $5 each.",
 "ua": "They cost $5 each."
 }
 ]
 },
 {
 "label": "Every - only before the noun",
 "color": "blue",
 "description": "<strong>Every</strong> is always <strong>only before noun</strong>.",
 "examples": [
 {
 "en": "Every student has a book. (‚úì)",
 "ua": "Every student has a book. (‚úì)"
 },
 {
 "en": "The students every have... (‚úó)",
 "ua": "The students every have... (‚úó)"
 }
 ]
 },
 {
 "label": "All ‚Äî before or with of",
 "color": "amber",
 "description": "<strong>All</strong> can: before a noun (without an article) or all of + article/possessive.",
 "examples": [
 {
 "en": "All students... (without article)",
 "ua": "All students... (without article)"
 },
 {
 "en": "All of the students... (with article)",
 "ua": "All of the students... (with article)"
 }
 ]
 }
 ]
}

{
 "title": "8. Common mistakes",
 "items": [
 {
 "label": "Error 1",
 "color": "rose",
 "title": "A plural verb with each/every.",
 "wrong": "Each student are... / Every person have...",
 "right": "‚Äã‚Äã‚Äã‚Äã <span class=\"font-mono\">Each student is... / Every person has...</span>"
 },
 {
 "label": "Error 2",
 "color": "amber",
 "title": "Use of 'every of'.",
 "wrong": "Every of the students passed.",
 "right": "‚Äã‚Äã‚Äã‚Äã <span class=\"font-mono\">Each of the students passed. All of the students passed. 4"
 },
 {
 "label": "Mistake 3",
 "color": "sky",
 "title": "Using a singular verb with all + plural noun.",
 "wrong": "All students is here.",
 "right": "‚úÖ <span class=\"font-mono\">All students are here.</span>"
 },
 {
 "label": "Mistake 4",
 "color": "purple",
 "title": "Every after a noun.",
 "wrong": "The students every have books.",
 "right": "‚Äã‚Äã‚Äã‚Äã <span class=\"font-mono\">Every student has a book. / The students each have a book.</span>"
 }
 ]
}

